const d = $input.first().json;
const history = JSON.parse(d.history_json || '[]');
const context = JSON.parse(d.context_json || '{}');

// Build conversation history text (last 14 messages)
let historialTexto = '';
if (history.length > 0) {
  const recientes = history.slice(-14);
  historialTexto = '\n\n[ConversaciГіn previa con este cliente]\n' +
    recientes.map(m => (m.role === 'human' ? 'Cliente: ' : 'Asistente: ') + m.content).join('\n') +
    '\n[Fin historial вҖ” continГәa naturalmente sin repetir saludos]';
}

// Context: property in consideration, lead already created, etc.
let ctxTexto = '';
if (context.property_id) {
  ctxTexto += `\n[Propiedad en discusiГіn: ID ${context.property_id}, wp_post_id ${context.wp_post_id || 0}]`;
}
if (context.lead_id) {
  ctxTexto += `\n[Lead ya registrado: ID ${context.lead_id} вҖ” NO volver a llamar registrar_lead]`;
}
if (context.cita_id) {
  ctxTexto += `\n[Cita ya agendada: ID ${context.cita_id} вҖ” NO volver a llamar agendar_cita]`;
}

return [{ json: {
  mensaje:        d.mensaje,
  numero:         d.numero,
  nombre:         d.nombre || '',
  fecha_contexto: d.fecha_contexto || '',
  historial:      historialTexto,
  ctx:            ctxTexto
}}];
